#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_N 100
#define MAX_M 100
#define MAX_K 10

int minMoves(int N, int M, int K1, int K2, int grid[N][M]) {
    int queue1[N * M][2];
    int queue2[N * M][2];
    int front1 = 0, rear1 = 0;
    int front2 = 0, rear2 = 0;
    int moves = 0;
    int dx[] = {-1, 1, 0, 0};
    int dy[] = {0, 0, -1, 1};

    queue1[rear1][0] = 0;
    queue1[rear1][1] = 0;
    rear1++;
    queue2[rear2][0] = 0;
    queue2[rear2][1] = M - 1;
    rear2++;

    while (front1 < rear1 || front2 < rear2) {
        if (front1 < rear1) {
            int x = queue1[front1][0];
            int y = queue1[front1][1];
            front1++;
            for (int i = 0; i < 4; i++) {
                int nx = x + dx[i];
                int ny = y + dy[i];
                if (nx >= 0 && nx < N && ny >= 0 && ny < M && grid[nx][ny] == 0 && abs(nx - x) + abs(ny - y) <= K1) {
                    if (nx == queue2[front2][0] && ny == queue2[front2][1]) {
                        return moves + 1;
                    }
                    queue1[rear1][0] = nx;
                    queue1[rear1][1] = ny;
                    rear1++;
                }
            }
        }
        if (front2 < rear2) {
            int x = queue2[front2][0];
            int y = queue2[front2][1];
            front2++;
            for (int i = 0; i < 4; i++) {
                int nx = x + dx[i];
                int ny = y + dy[i];
                if (nx >= 0 && nx < N && ny >= 0 && ny < M && grid[nx][ny] == 0 && abs(nx - x) + abs(ny - y) <= K2) {
                    if (nx == queue1[front1][0] && ny == queue1[front1][1]) {
                        return moves + 1;
                    }
                    queue2[rear2][0] = nx;
                    queue2[rear2][1] = ny;
                    rear2++;
                }
            }
        }
        moves++;
    }
    return -1;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M, K1, K2;
        scanf("%d %d %d %d", &N, &M, &K1, &K2);
        int grid[N][M];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                scanf("%d", &grid[i][j]);
            }
        }
        printf("%d\n", minMoves(N, M, K1, K2, grid));
    }
    return 0;
}

