    queue<pair<int, int>> q1;
    queue<pair<int, int>> q2;
    q1.push({0, 0});
    q2.push({0, M - 1});
    int moves = 0;
    int dx[] = {-1, 1, 0, 0};
    int dy[] = {0, 0, -1, 1};

    while (!q1.empty() || !q2.empty()) {
        if (!q1.empty()) {
            int x = q1.front().first;
            int y = q1.front().second;
            q1.pop();
            for (int i = 0; i < 4; i++) {
                int nx = x + dx[i];
                int ny = y + dy[i];
                if (nx >= 0 && nx < N && ny >= 0 && ny < M && grid[nx][ny] == 0 && abs(nx - x) + abs(ny - y) <= K1) {
                    if (nx == q2.front().first && ny == q2.front().second) {
                        return moves + 1;
                    }
                    q1.push({nx, ny});
                }
            }
        }
        if (!q2.empty()) {
            int x = q2.front().first;
            int y = q2.front().second;
            q2.pop();
            for (int i = 0; i < 4; i++) {
                int nx = x + dx[i];
                int ny = y + dy[i];
