import java.util.Queue;
import java.util.LinkedList;
import java.util.Scanner;

public class Main {
    static final int MAX_N = 100;
    static final int MAX_M = 100;
    static final int MAX_K = 10;

    public static int minMoves(int N, int M, int K1, int K2, int[][] grid) {
        Queue<int[]> q1 = new LinkedList<>();
        Queue<int[]> q2 = new LinkedList<>();
        q1.add(new int[] {0, 0});
        q2.add(new int[] {0, M - 1});
        int moves = 0;
        int dx[] = {-1, 1, 0, 0};
        int dy[] = {0, 0, -1, 1};

        while (!q1.isEmpty() || !q2.isEmpty()) {
            if (!q1.isEmpty()) {
                int x = q1.peek()[0];
                int y = q1.peek()[1];
                q1.poll();
                for (int i = 0; i < 4; i++) {
                    int nx = x + dx[i];
                    int ny = y + dy[i];
                    if (nx >= 0 && nx < N && ny >= 0 && ny < M && grid[nx][ny] == 0 && Math.abs(nx - x) + Math.abs(ny - y) <= K1) {
                        if (nx == q2.peek()[0] && ny == q2.peek()[1]) {
                            return moves + 1;
                        }
                        q1.add(new int[] {nx, ny});
                    }
                }
            }
            if (!q2.isEmpty()) {
                int x = q2.peek()[0];
                int y = q2.peek()[1];
                q2.poll();
                for (int i = 0; i < 4; i++) {
                    int nx = x + dx[i];
                    int ny = y + dy[i];
                    if (nx >= 0 && nx < N && ny >= 0 && ny < M && grid[nx][ny] == 0 && Math.abs(nx - x) + Math.abs(ny - y) <= K2) {
                        if (nx == q1.peek()[0] && ny == q1.peek()[1]) {
                            return moves + 1;
                        }
                        q2.add(new int[] {nx, ny});
                    }
                }
            }
            moves++;
        }
        return -1;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            int K1 = sc.nextInt();
            int K2 = sc.nextInt();
            int[][] grid = new int[N][M];
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < M; j++) {
                    grid[i][j] = sc.nextInt();
                }
            }
            System.out.println(minMoves(N, M, K1, K2, grid));
        }
    }
}

