from collections import deque

def minMoves(N, M, K1, K2, grid):
    q1 = deque([(0, 0)])
    q2 = deque([(0, M - 1)])
    moves = 0
    dx = [-1, 1, 0, 0]
    dy = [0, 0, -1, 1]

    while q1 or q2:
        if q1:
            x, y = q1.popleft()
            for i in range(4):
                nx, ny = x + dx[i], y + dy[i]
                if (0 <= nx < N and 0 <= ny < M and grid[nx][ny] == 0 and abs(nx - x) + abs(ny - y) <= K1):
                    if (nx, ny) == q2[0]:
                        return moves + 1
                    q1.append((nx, ny))
        if q2:
            x, y = q2.popleft()
            for i in range(4):
                nx, ny = x + dx[i], y + dy[i]
                if (0 <= nx < N and 0 <= ny < M and grid[nx][ny] == 0 and abs(nx - x) + abs(ny - y) <= K2):
                    if (nx, ny) == q1[0]:
                        return moves + 1
                    q2.append((nx, ny))
        moves += 1
    return -1

